/* eslint-disable react-hooks/rules-of-hooks */
import { useState, useEffect } from "react";
import axios from "axios";

export const clientCredentials = () => {
	const [userCreds, setUserCreds] = useState({ clientId: "", clientSecret: "" });
	const [credError, setCredError] = useState(null);
	const [loading, setLoading] = useState(true);

    // fetches the client credentials (client id and client secret from their spotify account)
	const fetchUserCredentials = async () => {
		await axios
			.get("http://localhost:3001/client")
			.then((res) => {
				setUserCreds({
					clientId: res.data?.client_id,
					clientSecret: res.data?.client_secret,
				});
			})
			.catch((err) => {
				console.log(err);
                setCredError(err);
			})
            .finally(() => {
                setLoading(false);
            })
	};

    // runs this function every time there is a new url
	useEffect(() => {
		fetchUserCredentials();
	}, [userCreds.clientId, userCreds.clientSecret]);

	return { userCreds, credError, loading };
};
